class Solution:
    def getErrorCount(self, rules: str) -> int:
        # 判断字符串是否是 1~9999 的合法数字
        def valid_num(s: str) -> bool:
            if not s or not s.isdigit():
                return False
            x = int(s)
            return 1 <= x <= 9999

        # 空串直接返回 0
        if not rules:
            return 0

        # 去掉整体首尾可能存在的双引号
        if len(rules) >= 2 and rules[0] == '"' and rules[-1] == '"':
            rules = rules[1:-1]

        # 按每条命令切分
        cmds = rules.split("][")

        # 哈希表：rule_id -> rule_index
        mp = {}
        ans = 0

        for cmd in cmds:
            # 去掉每条命令首尾可能残留的方括号
            cmd = cmd.strip("[]")
            parts = cmd.split()

            # 至少要有操作关键字
            if not parts:
                ans += 1
                continue

            op = parts[0]
            attrs = {}

            ok = True

            # 解析属性
            for i in range(1, len(parts)):
                if '=' not in parts[i]:
                    ok = False
                    break
                key, val = parts[i].split('=', 1)
                if key not in ("rule_id", "rule_index"):
                    ok = False
                    break
                if not valid_num(val):
                    ok = False
                    break
                attrs[key] = int(val)

            if not ok:
                ans += 1
                continue

            # 分类处理
            if op == "add_rule":
                # add 必须同时有 rule_id 和 rule_index
                if "rule_id" not in attrs or "rule_index" not in attrs:
                    ans += 1
                    continue
                rule_id = attrs["rule_id"]
                rule_index = attrs["rule_index"]
                if rule_id in mp:
                    ans += 1
                else:
                    mp[rule_id] = rule_index

            elif op == "mod_rule":
                # mod 必须同时有 rule_id 和 rule_index
                if "rule_id" not in attrs or "rule_index" not in attrs:
                    ans += 1
                    continue
                rule_id = attrs["rule_id"]
                rule_index = attrs["rule_index"]
                if rule_id not in mp or mp[rule_id] == rule_index:
                    ans += 1
                else:
                    mp[rule_id] = rule_index

            elif op == "del_rule":
                # del 只要求有 rule_id
                if "rule_id" not in attrs:
                    ans += 1
                    continue
                rule_id = attrs["rule_id"]
                if rule_id not in mp:
                    ans += 1
                else:
                    del mp[rule_id]

            else:
                # 非法操作关键字
                ans += 1

        return ans
