using namespace std;

class Solution {
public:
    int getErrorCount(string rules) {
        // 空串直接返回 0
        if (rules.empty()) {
            return 0;
        }

        // 去掉整体首尾可能存在的双引号
        if (rules.size() >= 2 && rules.front() == '"' && rules.back() == '"') {
            rules = rules.substr(1, rules.size() - 2);
        }

        // 按每条命令切分
        vector<string> cmds = splitCommands(rules);

        // 哈希表：rule_id -> rule_index
        unordered_map<int, int> mp;
        int ans = 0;

        for (string cmd : cmds) {
            // 去掉每条命令首尾可能残留的方括号
            cmd = trimBrackets(cmd);
            if (cmd.empty()) {
                ans++;
                continue;
            }

            vector<string> parts = splitBySpace(cmd);
            if (parts.empty()) {
                ans++;
                continue;
            }

            string op = parts[0];
            unordered_map<string, int> attrs;
            bool ok = true;

            // 解析属性
            for (int i = 1; i < (int)parts.size(); i++) {
                int pos = parts[i].find('=');
                if (pos == string::npos) {
                    ok = false;
                    break;
                }

                string key = parts[i].substr(0, pos);
                string val = parts[i].substr(pos + 1);

                if (key != "rule_id" && key != "rule_index") {
                    ok = false;
                    break;
                }

                if (!validNum(val)) {
                    ok = false;
                    break;
                }

                attrs[key] = stoi(val);
            }

            if (!ok) {
                ans++;
                continue;
            }

            // 分类处理
            if (op == "add_rule") {
                // add 必须同时有 rule_id 和 rule_index
                if (!attrs.count("rule_id") || !attrs.count("rule_index")) {
                    ans++;
                    continue;
                }

                int rule_id = attrs["rule_id"];
                int rule_index = attrs["rule_index"];

                if (mp.count(rule_id)) {
                    ans++;
                } else {
                    mp[rule_id] = rule_index;
                }

            } else if (op == "mod_rule") {
                // mod 必须同时有 rule_id 和 rule_index
                if (!attrs.count("rule_id") || !attrs.count("rule_index")) {
                    ans++;
                    continue;
                }

                int rule_id = attrs["rule_id"];
                int rule_index = attrs["rule_index"];

                if (!mp.count(rule_id) || mp[rule_id] == rule_index) {
                    ans++;
                } else {
                    mp[rule_id] = rule_index;
                }

            } else if (op == "del_rule") {
                // del 只要求有 rule_id
                if (!attrs.count("rule_id")) {
                    ans++;
                    continue;
                }

                int rule_id = attrs["rule_id"];

                if (!mp.count(rule_id)) {
                    ans++;
                } else {
                    mp.erase(rule_id);
                }

            } else {
                // 非法操作关键字
                ans++;
            }
        }

        return ans;
    }

private:
    // 判断字符串是否是 1~9999 的合法数字
    bool validNum(const string& s) {
        if (s.empty()) {
            return false;
        }
        for (char c : s) {
            if (c < '0' || c > '9') {
                return false;
            }
        }
        int x = stoi(s);
        return x >= 1 && x <= 9999;
    }

    // 去掉字符串首尾的 '[' 和 ']'
    string trimBrackets(const string& s) {
        int l = 0, r = (int)s.size() - 1;
        while (l <= r && s[l] == '[') l++;
        while (l <= r && s[r] == ']') r--;
        if (l > r) return "";
        return s.substr(l, r - l + 1);
    }

    // 按 "][" 切分命令
    vector<string> splitCommands(const string& s) {
        vector<string> res;
        int start = 0;
        for (int i = 0; i + 1 < (int)s.size(); i++) {
            if (s[i] == ']' && s[i + 1] == '[') {
                res.push_back(s.substr(start, i - start + 1));
                start = i + 1;
            }
        }
        res.push_back(s.substr(start));
        return res;
    }

    // 按空格切分
    vector<string> splitBySpace(const string& s) {
        vector<string> res;
        string cur;
        for (char c : s) {
            if (c == ' ') {
                if (!cur.empty()) {
                    res.push_back(cur);
                    cur.clear();
                }
            } else {
                cur.push_back(c);
            }
        }
        if (!cur.empty()) {
            res.push_back(cur);
        }
        return res;
    }
};
